        with pytest.raises(ImportError) as exc_info:
            GraceDbKafkaProducer("localhost:9092")

        assert "confluent-kafka is required" in str(exc_info.value)
        assert "pip install ligo-gracedb[kafka]" in str(exc_info.value)


